import{_ as a,o as i,c as r,ag as n}from"./chunks/framework.DXGyWiRo.js";const t="/images/lekt0102.jpg",s="/images/lekt0101.jpg",l="/images/lekt0103.jpg",h="/images/lekt0104.jpg",d="/images/lekt0105.jpg",o="/images/lekt0107.jpg",u="/images/lekt0108.jpg",c="/images/lekt0106.jpg",_=JSON.parse('{"title":"Lektion 1","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion01.md","filePath":"lektionen/lektion01.md"}'),g={name:"lektionen/lektion01.md"};function m(p,e,b,k,f,v){return i(),r("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-1" tabindex="-1">Lektion 1 <a class="header-anchor" href="#lektion-1" aria-label="Permalink to &quot;Lektion 1&quot;">​</a></h1><h3 id="गणेशपूजनम्" tabindex="-1">गणेशपूजनम् <a class="header-anchor" href="#गणेशपूजनम्" aria-label="Permalink to &quot;गणेशपूजनम्&quot;">​</a></h3><p>gaṇeśapūjanam<br> Verehrung des Gaṇeśa</p><p><img src="'+t+'" alt=""><br> Abb.: Gaṇeśa, Adamspeak, Sri Lanka<br> [Bildquelle: Wikipedia, gemeinfrei]</p><p>लम्बोदर नमस् तुभ्यं<br> सततं मोदकप्रिय |<br> निर्विघ्नं कुरु मे देव<br> सर्वकार्येषु सर्वदा ||</p><p>lambodara namas tubhyaṃ<br> satataṃ modakapriya |<br> nirvighnaṃ kuru me deva<br> sarvakāryeṣu sarvadā ||</p><p>Du Hängebauch, Du Naschkatze,<br> Stets sei Dir Verehrung!<br> Gott, mache all meine Unternehmungen<br> Frei von Hindernissen!</p><h3 id="मङ्गलचरणम्" tabindex="-1">मङ्गलचरणम् <a class="header-anchor" href="#मङ्गलचरणम्" aria-label="Permalink to &quot;मङ्गलचरणम्&quot;">​</a></h3><p>maṅgalacaraṇam<br> &quot;Glückbringender Anfang&quot;</p><p><img src="'+s+'" alt=""><br> Abb.: Ardhanarīśvara<br> (Bildquelle: Wikipedia, Public domain)</p><p>वागर्थाविव संपृक्तौ<br> वागर्थप्रतिपत्तये |<br> जगतः पितरौ वन्दे<br> पार्वतीपरमेश्वरौ ||</p><p>vāgarthāviva saṃpṛktau<br> vāgarthapratipattaye |<br> jagataḥ pitarau vande<br> pārvatīparameśvarau ||</p><p>(Kālidāsa: Raghuvaṃśa 1.1)</p><p>Ich grüße die Eltern der Welt,<br> Pārvatī und Śiva,<br> Die so fest miteinander verbunden sind<br> Wie Wort und Sinn zum Verständnis<br> Des Wortsinns.</p><h2 id="_1-0-ubersicht" tabindex="-1">1.0. Übersicht <a class="header-anchor" href="#_1-0-ubersicht" aria-label="Permalink to &quot;1.0. Übersicht&quot;">​</a></h2><ul><li>गणेशपूजनम् = gaṇeśapūjanam = Verehrung des Gaṇeśa</li><li>मङ्गलचरणम् = maṅgalacaraṇam = &quot;Glückbringender Anfang&quot;</li><li>1.1. Literatur für Anfänger in Indologie</li><li>1.2. Die Laute des Sanskrit nach der traditionellen indischen Klassifikation und ihre wissenschaftliche Umschrift <ul><li>1.2.1. Zur Aussprache einzelner Laute</li></ul></li><li>1.3. Übung</li></ul><p>Zu Beginn ein Kuriosum:</p><blockquote><p>&quot;Als William Jones [17461794] und Henry Thomas Colebrooke (17651857) das Sanskrit erstmalig gründlich studiert, teilweise übersetzt und gefunden hatten, dass es eine reiche Literatur und nicht geringe Verwandtschaft mit den klassischen Sprachen aufwies, stießen sie auf nicht geringen Widerstand. Da sich mit dieser innigen Beziehung des Sanskrits zu den geographisch so weit entlegenen europäischen Sprachen die alten Anschauungen, welche entweder alle Sprachen aus dem Hebräischen ableiteten oder größtenteils von einander isolierten, nicht in Einklang bringen lassen, so ergriff der berühmte Philologe Dugald Steward (17531828) den einfachsten Ausweg, indem er die ganze Geschichte mit der Sanskritsprache für eine Lüge erklärte. Er schrieb einen Essay, in dem er zu beweisen suchte, dass sie von den spitzbübischen Brahmanen nach dem Muster des Griechischen und Lateinischen zusammengeschmiedet sei und die Sprache sowohl als auch die Literatur eine Fälschung seien. Diese Ansicht entwickelte noch im Jahre 1840 der Professor in Dublin, Charles William Wall, weitläufig (Göttingische gelehrte Anzeigen 1842 S. 1888).&quot;</p><p>[Quelle: <strong>Kemmerich</strong>, Max &lt;1876-1932&gt;: Kultur-Kuriosa. -- München : Langen. -- Bd. 2. -- 1923. -- S. 74. -- Online: <a href="http://www.archive.org/details/kulturkuriosa02kemmuoft" target="_blank" rel="noreferrer">http://www.archive.org/details/kulturkuriosa02kemmuoft</a>. -- Zugriff am 2010-01-10]</p></blockquote><h2 id="_1-1-literatur-fur-anfanger-in-indologie" tabindex="-1">1.1. Literatur für Anfänger in Indologie <a class="header-anchor" href="#_1-1-literatur-fur-anfanger-in-indologie" aria-label="Permalink to &quot;1.1. Literatur für Anfänger in Indologie&quot;">​</a></h2><p><img src="'+l+'" alt=""><br> Abb.: Einbandtitel einer Taschenbuchausgabe</p><p><strong>Basham</strong>, A. L. (Arthur Llewellyn) &lt;1914-1986&gt;The wonder that was IndiaTeil: A survey of the culture of the Indian sub-continent before the coming of the Muslims. -- London : Sidgwick &amp; Jackson, 1954. -- Seither viele Ausgaben, auch Taschenbuchausgaben. -- Pflichtlektüre. Eine gute Übersicht über Leben, Geschichte und Kultur im vormuslimischen Indien. Gesamtübersicht über die verschiedenen Gebiete der klassischen Indologie.</p><p><img src="'+h+'" alt=""><br> Abb.: Titelblatt</p><p><strong>Beste systematische Grammatik</strong></p><p><strong>Kielhorn</strong>, Franz &lt;1840-1908&gt;: Grammatik der Sanskrit-Sprache / Aus dem Englischen übersetzt von W. Solf [1862 - 1936]. -- Berlin : Dümmler, 1888. -- XIII, 238 S. -- Originaltitel: A grammar of the Sanscrit language</p><p><img src="'+d+'" alt=""><br> Abb.: Umschlagtitel</p><p><strong>Gute systematische Grammatik auf der Grundlage der einheimischen Grammatiker und zugleich eine Einführung in Pāṇini:</strong></p><p><strong>Kunnappally, John:</strong> Prakriyā bhāshyam : Sanskrit grammar / Originally written in Malayalam. Translated into English by K.V.R. Pai. -- Parathode : Selbstverl., 1983. -- 818 S. ; 23 cm.</p><p><img src="'+o+'" alt=""><br> Abb.: Einbandtitel</p><p>Eine gute, knappe Darstellung der europäischen sprachwissenschaftlichen Terminologie findet man in:</p><blockquote><p><strong>Etymologisches Wörterbuch der deutschen Sprache</strong> / [Friedrich] Kluge&lt;1856 - 1926&gt;. Bearb. von Elmar Seebold. -- 24., durchges. und erw. Aufl.. -- Berlin [u.a.] : de Gruyter, 2002. - LXXXIX, 1023 S. : 24 cm. -- ISBN 3-11-017473-1 Paperback. -- S. XIII - XLVII.</p></blockquote><p><img src="'+u+'" alt=""><br> Abb.: Umschlagtitel</p><p>Für Wissbegierige zum Nachschlagen:</p><blockquote><p>Lexikon der Sprachwissenschaft / hrsg. von Hadumod Bußmann. -- 4., durchges. und bibliogr. erg. Aufl. / unter Mitarb. von Hartmut Lauffer. -- Stuttgart : Kröner, 2008. -- 816 S. ; 22 cm. -- ISBN 978-3-520-45204-7</p></blockquote><h2 id="_1-2-die-laute-des-sanskrit-nach-der-traditionellen-indischen-klassifikation-und-ihre-wissenschaftliche-umschrift" tabindex="-1">1.2. Die Laute des Sanskrit nach der traditionellen indischen Klassifikation und ihre wissenschaftliche Umschrift <a class="header-anchor" href="#_1-2-die-laute-des-sanskrit-nach-der-traditionellen-indischen-klassifikation-und-ihre-wissenschaftliche-umschrift" aria-label="Permalink to &quot;1.2. Die Laute des Sanskrit nach der traditionellen indischen Klassifikation und ihre wissenschaftliche Umschrift&quot;">​</a></h2><p><img src="'+c+'" alt=""></p><p>Moderne Wörterbücher des Sanskrit sind in der Reihenfolge dieser Klassifikation angeordnet. Diese Klassifikation und die Reihenfolge der Laute ist zum Verständnis der Sanskrit-Grammatik unerlässlich und muss deshalb auswendig gewusst werden:</p><blockquote><p>einfache Vokale (samānākṣara -- समानाक्षर):<br>  अ a, आ ā, इ i, ई ī, उ u, ऊ ū,  ऋ ṛ, ॠ ṝ, ऌ ḷ</p><p>Diphtonge (sandhyakṣara -- सन्ध्यक्षर):<br> ए e, ऐ ai, ओ o, औ au</p><p>Konsonanten (vyañjana / hal -- व्यञ्जन / हल्):<br> क ka, ख kha, ग ga, घ gha, ङ ṅa<br> च ca, छ cha, ज ja, झ jha, ञ ña<br> ट ṭa, ठ ṭha,  ड ḍa, ढ ḍha, ण ṇa<br> त ta, थ tha, द da, ध dha, न na<br> प pa, फ pha, ब ba, भ bha, म ma<br> य ya, र ra,  ल la, व va<br> श śa, ष ṣa, स sa<br> ह ha</p></blockquote><h3 id="_1-2-1-zur-aussprache-einzelner-laute" tabindex="-1">1.2.1. Zur Aussprache einzelner Laute <a class="header-anchor" href="#_1-2-1-zur-aussprache-einzelner-laute" aria-label="Permalink to &quot;1.2.1. Zur Aussprache einzelner Laute&quot;">​</a></h3><table tabindex="0"><thead><tr><th>a - अ</th><th>&quot;kurzes a&quot; wird bei den Indern -- schon seit alter Zeit -- oft wie ə ausgesprochen. In Europa spricht man es als kurzes a, in Bengalen als kurzes dunkles o.</th></tr></thead><tbody><tr><td>ṛ - ऋ</td><td>wie böhmisches vokalisiertes r. Leichter Nachklang von i.</td></tr><tr><td>ṝ - ॠ</td><td>wie böhmisches vokalisiertes r. Leichter Nachklang von u.</td></tr><tr><td>jñ - ज्ञ्</td><td>auch wie dny (Marāṭhī) oder gy (Nordindisch).</td></tr><tr><td>ś - श्</td><td>sch-Laut mit nach unten gebogener Zungenspitze. Ähnlich wie sch in &quot;mischen&quot;.</td></tr><tr><td>ṣ - ष्</td><td>ach-Laut mit zurückgebogener Zungenspitze. Öfters so weit hinten im Rachen artikuliert, dass es fast wie kh klingt.</td></tr><tr><td>h - ह्</td><td>Hauchlaut, nie Dehnungszeichen.</td></tr><tr><td>ḥ - :</td><td>Visarga (Visarjanīya) -- विसर्ग / विसर्जनीय. Stimmloser Hauchlaut mit Nachklang des vorhergehenden Vokals oder des zweiten Teils des vorausgehenden Diphtones: agniḥ -- अग्निः = agnihi, devaiḥ -- देवैः = devaihi, gauḥ -- गौः = gauhu</td></tr><tr><td>ṃ</td><td>Anusvara -- अनुस्वर</td></tr></tbody></table><ul><li>vor Zischlauten, h, l: Nasalierung des Vokals</li><li>im Auslaut = m</li><li>im Inlaut vor Konsonanten: der dem folgenden Konsonanten entsprechende Nasal: saṃdhi -- संधि = sandhi -- सन्धि</li></ul><p>|</p><p>Die beste Aussprache erreicht man, wenn man die Sätze, Verse oder Wörter ziemlich langsam und monoton mit genauer Berücksichtigung der Länge der Vokale liest.</p><h2 id="_1-3-ubung" tabindex="-1">1.3. Übung <a class="header-anchor" href="#_1-3-ubung" aria-label="Permalink to &quot;1.3. Übung&quot;">​</a></h2><p>A) Lesen Sie folgende Worte:</p><ol><li>varṇa brāhmaṇaḥ kṣatriya vaiśya śūdra -- वर्ण ब्राह्मणः क्षत्रिय वैश्य शूद्र</li><li>brahmā viṣṇu śiva -- ब्रह्मा विष्णु शिव</li><li>āśrama brāhmacārin gṛhastha vānaprastha saṃnyāsin -- आश्रम ब्राह्मचारिन् गृहस्थ वानप्रस्थ संन्यासिन्</li><li>ṛgveda sāmaveda yajurveda atharvaveda -- ऋग्वेद सामवेद यजुर्वेद अथर्ववेद</li><li>upaniṣad -- उपनिषद्</li><li>jaina bauddha -- जैन बौद्ध</li><li>prajñāpāramitā -- प्रज्ञापारमिता</li><li>cakra vajra -- चक्र वज्र</li><li>pitṝn -- पितॄन्</li><li>saṃskṛta -- संस्कृत</li></ol><p>B) Lesen Sie die Sanskrit-Ausdrücke in der Lautklassifikation oben.</p>',47)])])}const w=a(g,[["render",m]]);export{_ as __pageData,w as default};
